UPDATE t_p81888968_sergei_yalin_portfol.site_settings SET value = 'Родился в 1949 году. После окончания вечернего отделения МВТУ Баумана служил год на Финской границе помощником заместителя командира роты. Далее двадцать лет в МВД, подполковник внутренней службы. После переезда в г.Муром Владимирской области в 2013 году служил начальником штаба Муромского казачества. Сейчас являюсь прихожанином и звонарем храма Муромских святых Петра и Февронии. Пишу стихи и совместно с ИИ пишу песни православного содержания. Мой отец Михаил прошел войну до Берлина. Сын – участник второй Чеченской компании. Два внука служат по контракту в ВС России.' WHERE key = 'bio';